+			Healthy:     false,
+			Message:     fmt.Sprintf("dcg at %s not responding", path),
+			Error:       err.Error(),
+			LastChecked: time.Now(),
+			Latency:     latency,
+		}, nil
+	}
+
+	return &HealthStatus{
+		Healthy:     true,
+		Message:     "dcg is healthy",
+		LastChecked: time.Now(),
+		Latency:     latency,
+	}, nil
+}
